import { create } from 'zustand';
import { persist } from 'zustand/middleware';

type Inspection = { id: string; defects: Defect[]; syncedAt?: number };
type Defect = { id: string; severity: 'low' | 'high'; photo?: string };

type State = {
  inspections: Record<string, Inspection>;
  pending: Array<{ id: string; action: string; payload: unknown; tries: number }>;
};

type Actions = {
  addDefect: (inspectionId: string, defect: Defect) => Promise<void>;
  retrySync: () => Promise<void>;
};

export const useStore = create<State & Actions>()(
  persist(
    (set, get) => ({
      inspections: {},
      pending: [],
      addDefect: async (inspectionId, defect) => {
        const prev = get().inspections[inspectionId];
        if (!prev) throw new Error('inspection not found');
        // optimistic
        set((s) => ({
          inspections: {
            ...s.inspections,
            [inspectionId]: { ...prev, defects: [...prev.defects, defect] },
          },
          pending: [...s.pending, { id: defect.id, action: 'addDefect', payload: { inspectionId, defect }, tries: 0 }],
        }));
        try {
          await api.addDefect(inspectionId, defect);
          set((s) => ({ pending: s.pending.filter((p) => p.id !== defect.id) }));
        } catch (e) {
          // keep in pending queue, will retry
        }
      },
      retrySync: async () => {
        for (const p of get().pending) {
          try {
            if (p.action === 'addDefect') {
              const { inspectionId, defect } = p.payload as { inspectionId: string; defect: Defect };
              await api.addDefect(inspectionId, defect);
              set((s) => ({ pending: s.pending.filter((x) => x.id !== p.id) }));
            }
          } catch {
            // bump tries, dead-letter after N
          }
        }
      },
    }),
    { name: 'inspections-v1' },
  ),
);

import { createSlice, createEntityAdapter, configureStore, createListenerMiddleware, type PayloadAction } from '@reduxjs/toolkit';

type Defect = { id: string; inspectionId: string; severity: 'low' | 'high'; pending?: boolean };
const defectsAdapter = createEntityAdapter<Defect>();

const defectsSlice = createSlice({
  name: 'defects',
  initialState: defectsAdapter.getInitialState({ pendingIds: [] as string[] }),
  reducers: {
    addOptimistic: (state, a: PayloadAction<Defect>) => {
      defectsAdapter.upsertOne(state, { ...a.payload, pending: true });
      state.pendingIds.push(a.payload.id);
    },
    confirmSync: (state, a: PayloadAction<string>) => {
      const d = state.entities[a.payload];
      if (d) d.pending = false;
      state.pendingIds = state.pendingIds.filter((id) => id !== a.payload);
    },
  },
});

const syncMiddleware = createListenerMiddleware();
syncMiddleware.startListening({
  actionCreator: defectsSlice.actions.addOptimistic,
  effect: async (action, { dispatch }) => {
    try {
      await api.addDefect(action.payload);
      dispatch(defectsSlice.actions.confirmSync(action.payload.id));
    } catch {
      // stays pending, retry on reconnect
    }
  },
});

export const store = configureStore({
  reducer: { defects: defectsSlice.reducer },
  middleware: (gDM) => gDM().prepend(syncMiddleware.middleware),
});

