import { createContext, useContext, useState, type ReactNode } from 'react';

type SelectCtx<T> = {
  value: T | null;
  setValue: (v: T) => void;
  open: boolean;
  setOpen: (o: boolean) => void;
};

const Ctx = createContext<SelectCtx<unknown> | null>(null);
function useSelectCtx<T>(): SelectCtx<T> {
  const c = useContext(Ctx);
  if (!c) throw new Error('Select.* must be used inside Select.Root');
  return c as SelectCtx<T>;
}

function Root<T>({ children, defaultValue }: { children: ReactNode; defaultValue?: T }) {
  const [value, setValue] = useState<T | null>(defaultValue ?? null);
  const [open, setOpen] = useState(false);
  return <Ctx.Provider value={{ value, setValue, open, setOpen } as SelectCtx<unknown>}>{children}</Ctx.Provider>;
}

function Trigger({ children }: { children: ReactNode }) {
  const { open, setOpen } = useSelectCtx<unknown>();
  return <button aria-expanded={open} onClick={() => setOpen(!open)}>{children}</button>;
}

function Options({ children }: { children: ReactNode }) {
  const { open } = useSelectCtx<unknown>();
  if (!open) return null;
  return <ul role="listbox">{children}</ul>;
}

function Option<T>({ value, children }: { value: T; children: ReactNode }) {
  const ctx = useSelectCtx<T>();
  return (
    <li role="option" aria-selected={ctx.value === value} onClick={() => { ctx.setValue(value); ctx.setOpen(false); }}>
      {children}
    </li>
  );
}

export const SelectPrimitive = { Root, Trigger, Options, Option };

// Select.tsx - capped wrapper (8 props max)
type SelectProps<T> = {
  options: Array<{ value: T; label: string; disabled?: boolean }>;
  value: T | null;
  onChange: (v: T) => void;
  placeholder?: string;
  label: string;
  error?: string;
  disabled?: boolean;
  size?: 'sm' | 'md' | 'lg';
};

export function Select<T extends string | number>({ options, value, onChange, placeholder, label, error, size = 'md' }: SelectProps<T>) {
  return (
    <div className="flex flex-col gap-1">
      <label className="text-sm font-medium">{label}</label>
      <SelectPrimitive.Root defaultValue={value ?? undefined}>
        <SelectPrimitive.Trigger>
          {options.find((o) => o.value === value)?.label ?? placeholder ?? 'Select...'}
        </SelectPrimitive.Trigger>
        <SelectPrimitive.Options>
          {options.map((o) => (
            <SelectPrimitive.Option key={String(o.value)} value={o.value}>
              {o.label}
            </SelectPrimitive.Option>
          ))}
        </SelectPrimitive.Options>
      </SelectPrimitive.Root>
      {error && <span className="text-sm text-red-600">{error}</span>}
    </div>
  );
}

