import { useQueryClient } from '@tanstack/react-query';
function useApplyFilters() {
  const qc = useQueryClient();
  return (filters) => {
    setFilters(filters);
    qc.invalidateQueries({ queryKey: ['revenue'] });  // hierarchy invalidation
  };
}

