// Runtime theme loader
type BrandTheme = { primary: { l: number; c: number; h: number } };
export function applyBrand(theme: BrandTheme, mode: 'light' | 'dark') {
  const root = document.documentElement;
  const { l, c, h } = theme.primary;
  // Dark mode shifts L up for better visibility on dark bg
  const adjustedL = mode === 'dark' ? Math.min(0.85, l + 0.15) : l;
  root.style.setProperty('--primary-l', String(adjustedL));
  root.style.setProperty('--primary-c', String(c));
  root.style.setProperty('--primary-h', String(h));
  root.dataset.theme = mode;
}

