import { useEffect, useState, lazy, Suspense } from 'react';

const Lottie = lazy(() => import('lottie-react').then(m => ({ default: m.default })));

export function HeroAnimation() {
  const [shouldLoad, setShouldLoad] = useState(false);
  const [animationData, setAnimationData] = useState(null);

  useEffect(() => {
    // Show poster, load animation after hero is in view + idle
    if (typeof window === 'undefined') return;
    const idle = (window as any).requestIdleCallback ?? ((cb: () => void) => setTimeout(cb, 200));
    idle(() => {
      setShouldLoad(true);
      fetch('/animations/hero.json').then(r => r.json()).then(setAnimationData);
    });
  }, []);

  if (!shouldLoad || !animationData) {
    return <img src="/animations/hero-poster.webp" alt="" className="h-[400px] w-full object-cover" />;
  }
  return (
    <Suspense fallback={<img src="/animations/hero-poster.webp" alt="" />}>
      <Lottie animationData={animationData} loop autoplay />
    </Suspense>
  );
}

