type FieldProps =
  | { type: 'text'; value: string; onChange: (v: string) => void; placeholder?: string }
  | { type: 'number'; value: number; onChange: (v: number) => void; min?: number; max?: number }
  | { type: 'date'; value: Date; onChange: (v: Date) => void };

export function Field(props: FieldProps) {
  if (props.type === 'text') {
    return <input type="text" value={props.value} onChange={(e) => props.onChange(e.target.value)} />;
  }
  if (props.type === 'number') {
    return <input type="number" value={props.value} onChange={(e) => props.onChange(e.target.valueAsNumber)} min={props.min} max={props.max} />;
  }
  return <input type="date" value={props.value.toISOString().slice(0, 10)} onChange={(e) => props.onChange(new Date(e.target.value))} />;
}

