// Network layer (separate)
async function syncDocument(docId: string) {
  let attempts = 0;
  while (attempts < 3) {
    try {
      return await fetch(`/api/docs/${docId}`).then(r => r.json());
    } catch (e) {
      attempts++;
      if (attempts === 3) throw e;
      await new Promise(r => setTimeout(r, 500 * 2 ** attempts));
    }
  }
}

