import * as Y from 'yjs';
import { useSyncExternalStore } from 'react';

function useYMap<T extends Y.Map<any>>(map: T) {
  return useSyncExternalStore(
    (cb) => {
      const observer = () => cb();
      map.observe(observer);
      return () => map.unobserve(observer);
    },
    () => map.toJSON(),
    () => map.toJSON()
  );
}

export function useNote(noteDoc: Y.Doc) {
  const meta = useYMap(noteDoc.getMap('meta'));
  const body = useYMap(noteDoc.getMap('body'));
  const tags = useYMap(noteDoc.getMap('tags'));
  return { meta, body, tags };
}

import { create } from 'zustand';
import { nanoid } from 'nanoid';

type Toast = { id: string; type: 'success' | 'error' | 'info'; message: string };

type ToastStore = {
  toasts: Toast[];
  add: (t: Omit<Toast, 'id'>) => string;
  remove: (id: string) => void;
};

export const useToastStore = create<ToastStore>((set) => ({
  toasts: [],
  add: (t) => {
    const id = nanoid();
    set((s) => ({ toasts: [...s.toasts, { id, ...t }] }));
    setTimeout(() => set((s) => ({ toasts: s.toasts.filter((x) => x.id !== id) })), 4000);
    return id;
  },
  remove: (id) => set((s) => ({ toasts: s.toasts.filter((t) => t.id !== id) }))
}));

// Trigger functions
export const toast = {
  success: (message: string) => useToastStore.getState().add({ type: 'success', message }),
  error: (message: string) => useToastStore.getState().add({ type: 'error', message }),
  info: (message: string) => useToastStore.getState().add({ type: 'info', message })
};

// Renderer
export function ToastContainer() {
  const toasts = useToastStore((s) => s.toasts);
  return (
    <div className="fixed top-4 right-4 space-y-2">
      {toasts.map((t) => (
        <div key={t.id} className={`p-3 rounded shadow ${t.type === 'error' ? 'bg-danger' : 'bg-surface'}`}>
          {t.message}
        </div>
      ))}
    </div>
  );
}

import { useEffect, useRef } from 'react';

function useLinkPrefetch(href: string, ref: React.RefObject<HTMLAnchorElement>) {
  useEffect(() => {
    const link = ref.current;
    if (!link) return;
    const conn = (navigator as any).connection;
    if (conn?.saveData) return;
    let prefetched = false;
    const prefetch = () => {
      if (prefetched) return;
      prefetched = true;
      const l = document.createElement('link');
      l.rel = 'prefetch';
      l.href = href;
      document.head.appendChild(l);
    };
    // Desktop: hover
    link.addEventListener('mouseenter', prefetch);
    // Mobile: viewport
    const io = new IntersectionObserver((entries) => {
      if (entries[0].isIntersecting) prefetch();
    });
    io.observe(link);
    return () => {
      link.removeEventListener('mouseenter', prefetch);
      io.disconnect();
    };
  }, [href, ref]);
}

export function SmartLink({ href, children }: { href: string; children: React.ReactNode }) {
  const ref = useRef<HTMLAnchorElement>(null);
  useLinkPrefetch(href, ref);
  return <a ref={ref} href={href}>{children}</a>;
}

