export const transitions = {
  modalIn: { duration: 0.25, ease: [0, 0, 0.2, 1] },
  modalOut: { duration: 0.2, ease: [0.4, 0, 1, 1] },
  drawerSpring: { type: 'spring' as const, damping: 30, stiffness: 300 }
};

export function Modal({ open, children }: { open: boolean; children: React.ReactNode }) {
  const reduced = useReducedMotion();
  return (
    <motion.div
      initial={{ opacity: 0, scale: 0.96 }}
      animate={{ opacity: open ? 1 : 0, scale: open ? 1 : 0.96 }}
      transition={reduced ? { duration: 0.01 } : transitions.modalIn}
    >
      {children}
    </motion.div>
  );
}

export function BottomSheet({ y, onDragEnd }: { y: number; onDragEnd: (y: number) => void }) {
  return (
    <motion.div
      drag="y"
      style={{ y }}
      onDragEnd={(_, info) => onDragEnd(info.offset.y)}
      transition={transitions.drawerSpring}
    />
  );
}

