// features/billing/domain/prorate.ts (pure, no React)
export function prorate(
  currentPlan: Plan,
  newPlan: Plan,
  daysInBillingPeriod: number,
  daysRemainingInPeriod: number
): { creditAmount: number; chargeAmount: number } {
  const dailyRateOld = currentPlan.monthlyPrice / daysInBillingPeriod;
  const dailyRateNew = newPlan.monthlyPrice / daysInBillingPeriod;
  return {
    creditAmount: dailyRateOld * daysRemainingInPeriod,
    chargeAmount: dailyRateNew * daysRemainingInPeriod
  };
}

