import { useOptimistic, useTransition } from 'react';

function LikeButton({ postId, initialLiked }: { postId: string; initialLiked: boolean }) {
  const [optimisticLiked, setOptimisticLiked] = useOptimistic(initialLiked);
  const [pending, startTransition] = useTransition();

  const toggleLike = () => {
    startTransition(async () => {
      setOptimisticLiked(!optimisticLiked);
      try {
        await fetch(`/api/posts/${postId}/like`, { method: optimisticLiked ? 'DELETE' : 'POST' });
      } catch {
        // useOptimistic auto-reverts when action completes; nothing to do
      }
    });
  };

  return (
    <button onClick={toggleLike} disabled={pending} className={optimisticLiked ? 'liked' : ''}>
      {optimisticLiked ? 'Liked' : 'Like'}
    </button>
  );
}
